-	if (pthread_create(&thread[i], NULL, server, &args[i]) < 0) {
+	if (pthread_create(&thread[i], NULL, server, &args[i]) != 0) {
 	    perror("failed to create server thread");
 	    return -1;
         }
@@ -393,7 +393,7 @@
     }

     for (int i = 0; i < clients; i++) {
-        if (pthread_join(thread[i], NULL) < 0) {
+        if (pthread_join(thread[i], NULL) != 0) {
  	    perror("failed to join thread");
